import{_ as a,o,c as t,a3 as c}from"./chunks/framework.aYYe0dfI.js";const f=JSON.parse('{"title":"Module extract:filter","description":"extract:filter 模块负责对路径标识符进行提取、过滤和规范化操作。它公开了一系列以整数参数传递路径标识的函数，包括将路径转换为过滤后的根路径标识、生成规范化的图路径、相对于指定目录解析路径、检查路径前缀匹配、应用内部过滤条件以及计算项目相对路径。模块依赖 config 获取配置数据，并依赖标准库实现底层路径处理。","frontmatter":{"title":"Module extract:filter","description":"extract:filter 模块负责对路径标识符进行提取、过滤和规范化操作。它公开了一系列以整数参数传递路径标识的函数，包括将路径转换为过滤后的根路径标识、生成规范化的图路径、相对于指定目录解析路径、检查路径前缀匹配、应用内部过滤条件以及计算项目相对路径。模块依赖 config 获取配置数据，并依赖标准库实现底层路径处理。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/filter.md","filePath":"zh/clore/modules/extract/filter.md"}'),r={name:"zh/clore/modules/extract/filter.md"};function d(l,e,i,s,n,h){return o(),t("div",null,[...e[0]||(e[0]=[c('<h1 id="module-extract-filter" tabindex="-1">Module <code>extract:filter</code> <a class="header-anchor" href="#module-extract-filter" aria-label="Permalink to &quot;Module `extract:filter`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>extract:filter</code> 模块负责对路径标识符进行提取、过滤和规范化操作。它公开了一系列以整数参数传递路径标识的函数，包括将路径转换为过滤后的根路径标识、生成规范化的图路径、相对于指定目录解析路径、检查路径前缀匹配、应用内部过滤条件以及计算项目相对路径。模块依赖 <code>config</code> 获取配置数据，并依赖标准库实现底层路径处理。</p><p>该模块拥有的公共实现范围包括：路径解析、前缀匹配、过滤判定和相对路径计算，同时提供 <code>PathResolveError</code> 错误类型用于报告路径解析失败时的信息。所有公开函数都操作预先注册的路径标识符，不直接执行文件系统 I/O，调用方需确保传入的标识符有效。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./merge"><code>extract:merge</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-pathresolveerror" tabindex="-1"><code>clore::extract::PathResolveError</code> <a class="header-anchor" href="#clore-extract-pathresolveerror" aria-label="Permalink to &quot;`clore::extract::PathResolveError`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:8</code></p><p>Definition: <code>extract/filter.cppm:8</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::PathResolveError</code> 是一个简单的错误类型，其内部仅包含一个 <code>message</code> 数据成员，类型为 <code>std::string</code>。该成员存储描述错误原因的可读文本。结构体没有用户定义的构造函数、析构函数或赋值操作符，完全依赖编译器生成的默认实现，因此其值语义与底层字符串一致。唯一隐含的不变量是 <code>message</code> 应包含有效的错误描述（通常由调用方保证），但结构体本身不强制执行任何约束。这种设计使其成为极轻量的结果封装，适合作为 <code>tl::expected</code> 或类似模式中的错误类型使用。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>message</code> member contains a description of the error.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned by functions that perform path resolution to indicate failure.</li><li>Calling code can inspect <code>message</code> to display or log the error.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-canonical-graph-path" tabindex="-1"><code>clore::extract::canonical_graph_path</code> <a class="header-anchor" href="#clore-extract-canonical-graph-path" aria-label="Permalink to &quot;`clore::extract::canonical_graph_path`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:21</code></p><p>Definition: <code>extract/filter.cppm:103</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::canonical_graph_path</code> 实现了一个多级回退的路径规范化算法，旨在将给定的 <code>std::filesystem::path</code> 转换为尽可能规范的通用字符串表示。其核心流程首先通过 <code>std::filesystem::absolute</code> 将输入路径转为绝对形式，并使用 <code>std::error_code</code> 捕获可能的错误；若成功，则进一步调用 <code>std::filesystem::weakly_canonical</code> 配合 <code>lexically_normal</code> 生成规范路径，若全部成功则直接返回其通用字符串；若 <code>absolute</code> 阶段失败，则降级为对原始路径进行 <code>lexically_normal</code> 之后再尝试 <code>weakly_canonical</code>，同样通过错误码判断成功与否；若所有 <code>weakly_canonical</code> 尝试均失败，则最终返回仅经过 <code>lexically_normal</code> 处理的通用字符串。整个过程依赖 <code>std::filesystem</code> 库的路径操作函数，未引入外部项目内的依赖。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>path</code> parameter</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to obtain a unique, normalised graph path for file-based nodes</li><li>called during graph construction to canonicalize source file paths</li></ul><h3 id="clore-extract-filter-root-path" tabindex="-1"><code>clore::extract::filter_root_path</code> <a class="header-anchor" href="#clore-extract-filter-root-path" aria-label="Permalink to &quot;`clore::extract::filter_root_path`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:27</code></p><p>Definition: <code>extract/filter.cppm:161</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数依据 <code>config::TaskConfig</code> 中的工作区根路径配置进行决策：若 <code>config.workspace_root</code> 非空，则直接构造 <code>std::filesystem::path</code> 并调用 <code>lexically_normal()</code> 规范化后返回；否则回退至 <code>config.project_root</code>，同样经过 <code>lexically_normal()</code> 处理。其内部不涉及异常处理或路径存在性校验，仅通过条件分支选择规范化路径作为 <code>filter_root_path</code> 的结果。依赖包括 <code>std::filesystem::path</code> 的构造与规范化方法，以及 <code>config::TaskConfig</code> 的成员访问。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>config::TaskConfig::workspace_root</code></li><li><code>config::TaskConfig::project_root</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to obtain a canonical root path for filtering operations</li><li>Called when a normalized base directory is required</li></ul><h3 id="clore-extract-matches-filter" tabindex="-1"><code>clore::extract::matches_filter</code> <a class="header-anchor" href="#clore-extract-matches-filter" aria-label="Permalink to &quot;`clore::extract::matches_filter`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:23</code></p><p>Definition: <code>extract/filter.cppm:124</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::matches_filter</code> 首先通过 <code>canonical_graph_path</code> 规范化输入的两个路径 <code>file</code> 和 <code>filter_root</code>，生成 <code>file_path</code> 与 <code>root_path</code>。随后调用 <code>project_relative_path</code> 尝试计算从 <code>root_path</code> 到 <code>file_path</code> 的相对路径；若计算失败（返回空 optional），则直接返回 <code>false</code>。成功后将相对路径转换为通用字符串 <code>relative_str</code>。接着处理 <code>filter</code> 的 <code>include</code> 规则：若该列表非空，则遍历每个 <code>pattern</code> 并调用 <code>path_prefix_matches</code> 检查 <code>relative_str</code> 是否匹配，一旦发现匹配则设置标记并跳出；若全部遍历后未匹配任何 <code>include</code> 规则，函数返回 <code>false</code>。之后处理 <code>exclude</code> 规则：遍历每个 <code>pattern</code>，只要 <code>path_prefix_matches</code> 返回 <code>true</code> 即命中排除规则，立即返回 <code>false</code>。若所有检查均通过，最终返回 <code>true</code>。整个流程依赖于 <code>canonical_graph_path</code>、<code>project_relative_path</code> 和 <code>path_prefix_matches</code> 三个辅助函数完成路径解析与模式匹配。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>file</code> parameter</li><li><code>filter_root</code> parameter</li><li><code>filter.include</code> and <code>filter.exclude</code> member vectors</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to determine if a source file should be processed based on filtering rules</li></ul><h3 id="clore-extract-path-prefix-matches" tabindex="-1"><code>clore::extract::path_prefix_matches</code> <a class="header-anchor" href="#clore-extract-path-prefix-matches" aria-label="Permalink to &quot;`clore::extract::path_prefix_matches`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:12</code></p><p>Definition: <code>extract/filter.cppm:33</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数检查给定的 <code>relative</code> 路径是否以 <code>pattern</code> 为前缀，并确保匹配发生在完整的路径段边界上。算法首先处理 <code>pattern</code> 为空或尾部有多余斜杠的边缘情况，将其规范化。若 <code>pattern</code> 本身包含斜杠，则要求 <code>relative</code> 以 <code>pattern</code> 整体开头，且要么两者等长，要么紧随匹配部分之后是一个 <code>/</code> 分隔符。若 <code>pattern</code> 不含斜杠（仅匹配一个路径组件），则要求 <code>relative</code> 比 <code>pattern</code> 至少长一个字符、以 <code>pattern</code> 开头，且第 <code>pattern.size()</code> 个字符是 <code>/</code>，或者两者完全相等。</p><p>内部控制流围绕 <code>while</code> 循环移除尾部斜杠，随后根据 <code>pattern</code> 是否含有 <code>/</code> 分支处理。所有比较均通过 <code>std::string_view</code> 的 <code>starts_with</code> 和索引访问完成，未引入额外依赖。该函数是纯谓词，不涉及文件系统操作或外部状态，仅依赖标准字符串视图功能。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>relative</code> of type <code>std::string_view</code></li><li>parameter <code>pattern</code> of type <code>std::string_view</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to filter paths by a prefix pattern</li><li>likely called during project model filtering or path matching</li></ul><h3 id="clore-extract-project-relative-path" tabindex="-1"><code>clore::extract::project_relative_path</code> <a class="header-anchor" href="#clore-extract-project-relative-path" aria-label="Permalink to &quot;`clore::extract::project_relative_path`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:14</code></p><p>Definition: <code>extract/filter.cppm:64</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::project_relative_path</code> 首先对输入的 <code>file</code> 路径调用 <code>std::filesystem::path::lexically_relative</code>，以 <code>root_path</code> 为基准进行词法相对化，结果存入 <code>rel</code>。若 <code>rel</code> 为空（表示两路径无公共前缀或相同），则立即返回 <code>std::nullopt</code>。随后遍历 <code>rel</code> 的每个组件，若任一组件等于 <code>..</code>，表明相对路径会跳出 <code>root_path</code> 范围，同样返回 <code>std::nullopt</code>。上述检查均通过后，直接返回 <code>rel</code>。</p><p>该实现仅依赖标准库的 <code>std::filesystem::path</code> 及相关操作，不调用任何自定义辅助函数。核心控制流为“词法计算 → 空值检验 → 向上遍历检验 → 返回结果”，保证了仅输出不包含父目录引用的严格相对路径。若无法计算或路径不合法，始终以 <code>std::nullopt</code> 表示失败。</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>the <code>file</code> parameter</li><li>the <code>root_path</code> parameter</li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li><code>project_relative_path(file_path, project_root)</code></li><li>determining whether a file is under a project root and its relative path</li></ul><h3 id="clore-extract-resolve-path-under-directory" tabindex="-1"><code>clore::extract::resolve_path_under_directory</code> <a class="header-anchor" href="#clore-extract-resolve-path-under-directory" aria-label="Permalink to &quot;`clore::extract::resolve_path_under_directory`&quot;">​</a></h3><p>Declaration: <code>extract/filter.cppm:18</code></p><p>Definition: <code>extract/filter.cppm:79</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数首先检查输入 <code>path</code> 是否为空字符串，若为空则立即以 <code>PathResolveError</code> 结构体返回错误，其中 <code>message</code> 字段包含描述信息。随后将 <code>path</code> 转换为 <code>std::filesystem::path</code> 对象 <code>p</code>，并依据其相对性判断：若 <code>p</code> 是相对路径（<code>p.is_relative()</code> 为真），则必须保证 <code>directory</code> 非空，否则返回另一条错误消息；若 <code>directory</code> 非空，则拼接为 <code>fs::path(directory) / p</code> 生成绝对路径。若 <code>p</code> 原本就是绝对路径则直接使用。最终对结果调用 <code>p.lexically_normal()</code> 得到标准化路径并返回。</p><p>整个流程仅依赖标准库中的 <code>std::filesystem</code> 路径处理函数（<code>is_relative</code>、<code>operator/</code>、<code>lexically_normal</code>），未涉及实际文件系统状态查询。错误处理均通过 <code>std::unexpected</code> 配合 <code>PathResolveError</code> 结构体传递，不抛出异常。</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>path</code> parameter (string)</li><li><code>directory</code> parameter (string)</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>resolve compilation database file paths</li><li>normalize relative paths against a base directory</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>模块 <code>extract:filter</code> 将路径解析与过滤逻辑分解为两个层次。底层提供一组路径工具函数（<code>canonical_graph_path</code>、<code>resolve_path_under_directory</code>、<code>project_relative_path</code>、<code>path_prefix_matches</code>），负责路径的规范化、相对化及前缀匹配；上层实现过滤策略（<code>matches_filter</code>、<code>filter_root_path</code>），结合 <code>PathResolveError</code> 处理异常。它从 <code>config</code> 模块导入过滤所需的根路径和模式配置，依赖 <code>std</code> 模块提供基础类型与错误码支持。内部变量（如 <code>config</code>、<code>filter_root</code>、<code>pattern</code>）在各函数间共享，共同维护路径与过滤器的状态。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li></ul>',94)])])}const m=a(r,[["render",d]]);export{f as __pageData,m as default};
